SELECT qs.*, qas.id AS qas_id, qas.create_time AS qas_create_time, qas.update_time AS qas_update_time, qas.is_deleted AS qas_is_deleted FROM questions AS qs LEFT JOIN question_answers AS qas ON qs.id = qas.question_id WHERE qs.is_deleted = 0 AND qas.is_deleted = 0
AND qs.type = #{queryVo.type}
AND qs.difficulty = #{queryVo.difficulty}
AND qs.category_id = #{queryVo.categoryId}
AND title LIKE CONCAT('%', #{queryVo.keyword}, '%')
ORDER BY qs.id DESC

SELECT qs.*, qas.id AS qas_id, qas.question_id, qas.answer, qas.keywords, qas.create_time AS qas_create_time, qas.update_time AS qas_update_time, qcs.id AS qcs_id, qcs.question_id AS qcs_question_id, qcs.content, qcs.is_correct, qcs.sort, qcs.create_time AS qcs_create_time, qcs.update_time AS qcs_update_time FROM questions qs LEFT JOIN question_answers qas ON qs.id = qas.question_id LEFT JOIN question_choices qcs ON qs.id = qcs.question_id AND qcs.is_deleted = 0 WHERE qs.is_deleted = 0 AND qas.is_deleted = 0
AND qs.category_id = #{categoryId}
AND qs.difficulty = #{difficulty}
ORDER BY RAND() LIMIT #{count}
